"""
MKT Christ Commentary — Matthew chapter 25
Run: python3 scripts/zc-christ-matthew-25-25.py

Key decisions:
- Ten Virgins (25:1-13): classified as direct revelation — Jesus is the bridegroom
  (self-identification from 9:15); "I do not know you" is the eschatological exclusion
  pronounced by Christ himself; the parable is the final watchfulness parable
  closing the Olivet Discourse
- Talents (25:14-30): classified as revelation of God — the master's returning
  after a long journey = Christ at the parousia; the talents = entrusted kingdom
  resources; v.29 repeats the abundance-to-the-having principle (13:12)
- Sheep and Goats (25:31-46): classified as direct revelation at every verse —
  the most explicit eschatological Christology in Matthew; the Son of Man on the
  throne identifies Jesus as the Danielic judge; the solidarity with "the least of
  these my brothers" is the highest christological identification with the vulnerable
  in the entire Gospel
- 25:40 and 25:45 ("as you did to the least of these... you did to me") are the
  central Christological claims of the passage — the king who identifies himself
  with the hungry, thirsty, stranger, naked, sick, and imprisoned
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "25": {
    "1": '<p>A direct revelation: "Then the kingdom of heaven will be like ten virgins who took their lamps and went to meet the bridegroom." The bridegroom-identification is the Christological key: Jesus identified himself as the bridegroom in 9:15 ("the wedding guests mourn as long as the bridegroom is with them"). The ten virgins represent the waiting community of the kingdom — those who have received the invitation and are positioned to receive the bridegroom when he arrives. The parable closes the watchfulness section of the Olivet Discourse with the image that reveals most clearly who is coming.</p>',
    "2": '<p>A revelation of God: "Five of them were foolish, and five were wise." The equal division — five foolish, five wise — is the Christological diagnostic: the community of those who wait for the bridegroom is mixed. The foolish and wise are not the unconverted and the converted but the unprepared and the prepared within the waiting community. The Christological warning: position (waiting for the bridegroom) is not the same as preparation (oil in the lamp).</p>',
    "3": '<p>A revelation of God: "For when the foolish took their lamps, they took no oil with them." The absence of oil — the substance that sustains the flame — is the Christological image of inner spiritual resource. The lamp without oil is the external form of faith without the interior life that sustains it. The foolish virgins have the correct position (waiting) and the correct equipment (lamps) but lack the substance that would enable them to meet the bridegroom when he finally arrives.</p>',
    "4": '<p>A revelation of God: "But the wise took flasks of oil with their lamps." The extra flask of oil — the supplementary supply — is the Christological image of the prepared disciple who has built into ordinary life the resource for sustained waiting. The wise do not merely have enough for the expected arrival time; they have provision for delay. The Christological bearing: the readiness that survives the long wait is not the fervor of initial reception but the deep reserve that carries the flame through the night.</p>',
    "5": '<p>A revelation of God: "As the bridegroom was delayed, all ten of them became drowsy and slept." The sleep of all ten — wise and foolish alike — is the Christological realism about the parousia\'s delay: even the prepared will experience the weariness of long waiting. The sleep is not a failure of the wise but the universal condition of those who wait through the night. The Christological bearing: the delay tests not alertness at each moment but the deep provision of oil that will sustain the flame when the midnight cry comes.</p>',
    "6": '<p>A revelation of God: "But at midnight there was a cry, \'Here is the bridegroom! Come out to meet him.\'" The midnight cry is the eschatological announcement that interrupts the sleep of all ten. The hour — midnight, the darkest moment, when the delay has been longest and the expectation most strained — is the Christological timing of the parousia: unexpected (24:42), at the moment least anticipated, in the deepest darkness. The community that has maintained its oil through the night can respond; those who have not are exposed.</p>',
    "7": '<p>A revelation of God: "Then all those virgins rose and trimmed their lamps." The universal response — all ten rise and trim — is the Christological equalizer: the cry goes to all, the action is the same. The difference appears only when the lamps are lit: the wise have oil, the foolish do not. The Christological test is not the response to the announcement but the condition that was maintained before the announcement. Preparation precedes the test; the test only reveals what was already true.</p>',
    "8": '<p>A revelation of God: "And the foolish said to the wise, \'Give us some of your oil, for our lamps are going out.\'" The request for oil from the wise to the foolish is the Christological impossibility: the inner spiritual resource that sustains readiness cannot be transferred. The oil of genuine faith, genuine prayerfulness, genuine relationship with the bridegroom — these cannot be borrowed or given. Each person must have their own. The Christological warning: communal position does not substitute for personal preparation.</p>',
    "9": '<p>A revelation of God: "But the wise answered, saying, \'Since there will not be enough for us and for you, go rather to the dealers and buy for yourselves.\'" The wise virgins\' refusal is not selfishness but the recognition of reality: the oil they have is for their lamps, and giving it away would leave them unready too. The instruction to "buy for yourselves" is the Christological call to individual accountability. In the moment of crisis, each person must have their own resource. The communal life of the kingdom does not eliminate individual responsibility before the bridegroom.</p>',
    "10": '<p>A direct revelation: "And while they were going to buy, the bridegroom came, and those who were ready went in with him to the marriage feast, and the door was shut." The door shut while the foolish are away buying oil is the Christological moment of eschatological finality. Those who were ready — oil-sustained, lamps burning — enter with the bridegroom. The wedding feast that begins behind the closed door is the eschatological joy of the kingdom. The door closed is not cruelty but the irreversibility of the moment of arrival: the bridegroom came, the ready entered, and the feast began.</p>',
    "11": '<p>A direct revelation: "Afterward the other virgins came also, saying, \'Lord, lord, open to us.\'" The "Lord, lord" plea of the late-arriving virgins echoes 7:21-22 ("not everyone who says to me \'Lord, Lord\' will enter the kingdom of heaven"). The title is correct; the relationship is absent. The Christological diagnostic: the invocation of the Lord\'s name is not the same as the relationship with the Lord that produces sustained readiness. The bridegroom is the Lord; calling him Lord is not the same as knowing him.</p>',
    "12": '<p>A direct revelation: "But he answered, \'Truly, I say to you, I do not know you.\'" The "I do not know you" is the most severe Christological statement of the parable — the bridegroom\'s rejection of the latecomers who called him Lord. "I do not know you" is not ignorance but the relational verdict: there is no existing relationship that the arrival can build on. The oil-less lamp is the image of the life without the sustaining relationship with the bridegroom. The eschatological exclusion names the absence of that relationship.</p>',
    "13": '<p>A direct revelation: "Watch therefore, for you know neither the day nor the hour." The closing command — "watch" (<em>grēgorein</em>) — is the Christological application of the parable to the community\'s present condition. The ignorance of day and hour is precisely the condition of the disciples (24:36). The bridegroom will come; the hour is unknown; watchfulness is the only appropriate response to that combination of certainty and ignorance. The parable has named who is coming (the bridegroom, the Lord) and what preparation requires (sustained inner resource).</p>',
    "14": '<p>A revelation of God: "For it will be like a man going on a journey, who called his servants and entrusted to them his property." The Talents parable begins with the same structure as the Faithful and Wicked Servants (24:45-51): a master who departs, leaving servants with responsibilities. The entrusting of property (<em>hyparchonta</em>, possessions) is the Christological model of the kingdom\'s distribution: the returning Lord has left resources in his servants\' hands during his absence. The parousia is the return of the master who will evaluate the stewardship.</p>',
    "15": '<p>A revelation of God: "To one he gave five talents, to another two, to another one, to each according to his ability. Then he went away." The distribution "according to ability" is the Christological recognition of differential capacity: the master gives each what they can manage. The talents are not equal, but the expectation is proportional — faithful management of whatever is given, not a uniform performance. The Christological bearing: the question at the parousia is not "how much did you produce?" but "were you faithful with what was given?"</p>',
    "16": '<p>A revelation of God: "He who had received the five talents went at once and traded with them, and he made five talents more." The five-talent servant\'s immediate action — "went at once" — is the Christological model of urgent, unsupervised faithfulness. He does not wait for the master\'s return to begin; he acts immediately with what was entrusted. The doubling of the investment is the fruit of active, engaged stewardship. The Christological standard: the absent master expects the same engagement as if he were present.</p>',
    "17": '<p>A revelation of God: "So also he who had the two talents made two talents more." The two-talent servant follows the same pattern: received two, gained two more. The percentage is the same; the absolute amount is different. The Christological equity: the commendation (v.23) will be identical to the five-talent servant\'s (v.21) — "well done, good and faithful servant." The kingdom measures faithfulness, not productivity. Both servants are equally faithful; both receive the same reward.</p>',
    "18": '<p>A revelation of God: "But he who had received the one talent went and dug in the ground and hid his master\'s money." The one-talent servant\'s burial of the talent is the Christological anti-type of faithful stewardship: hiding what was given rather than risking it in use. The burying is not theft but refusal to act. The Christological bearing: the kingdom\'s resources are not given to be stored but to be invested. A talent buried is a talent that has no kingdom effect.</p>',
    "19": '<p>A revelation of God: "Now after a long time the master of those servants came and settled accounts with them." The "long time" is the Christological acknowledgment of the parousia\'s delay — the same delay that the wicked servant exploited (24:48) and the foolish virgins failed to prepare for (25:5). The settling of accounts is the judgment scene; the master who returns is the Son of Man who sits on his glorious throne (v.31). The parable and the Sheep and Goats share the same returning-master/judge figure.</p>',
    "20": '<p>A direct revelation: "And he who had received the five talents came forward, bringing five talents more, saying, \'Master, you delivered to me five talents; here I have made five talents more.\'" The five-talent servant\'s account is the Christological model of transparent stewardship: he presents his work fully, with the original and the gain together. The "master, you delivered to me" is the acknowledgment that what he managed was never his own but entrusted. The Christological servant knows the difference between ownership and stewardship.</p>',
    "21": '<p>A direct revelation: "His master said to him, \'Well done, good and faithful servant. You have been faithful over a little; I will set you over much. Enter into the joy of your master.\'" The commendation — "well done, good and faithful servant" — is the Christological reward that every disciple seeks. "Enter into the joy of your master" (<em>eiselthe eis tēn charan tou kyriou sou</em>) is the language of the eschatological banquet: entry into the master\'s own joy, sharing the bridegroom\'s happiness at the wedding feast. The kingdom\'s reward is not wages for labor but participation in the master\'s own life.</p>',
    "22": '<p>A revelation of God: "And he also who had the two talents came forward, saying, \'Master, you delivered to me two talents; here I have made two talents more.\'" The two-talent servant\'s presentation mirrors the five-talent servant\'s exactly. The Christological equity of the kingdom: identical faithfulness with different amounts receives identical commendation. The kingdom does not penalize the servant who had less to begin with; it evaluates whether what was given was used.</p>',
    "23": '<p>A direct revelation: "His master said to him, \'Well done, good and faithful servant. You have been faithful over a little; I will set you over much. Enter into the joy of your master.\'" The word-for-word identical commendation for the two-talent servant is the Christological equality of the kingdom\'s reward: the same "well done," the same eschatological promotion, the same entry into the master\'s joy. Two talents, same faithfulness, same reward. The principle that the kingdom rewards proportional faithfulness means identical response to identical faithfulness regardless of scale.</p>',
    "24": '<p>A revelation of God: "He also who had received the one talent came forward, saying, \'Master, I knew you to be a hard man, reaping where you did not sow, and gathering where you scattered no seed.\'" The one-talent servant\'s characterization of the master — hard, unjust, extractive — is the Christological diagnostic of fear-based unfaithfulness. He has an image of the master that is false: the master who gives talents, commends faithful service, and invites servants into his joy is not hard. The servant\'s fear reveals a distorted theology that produces paralysis.</p>',
    "25": '<p>A revelation of God: "So I was afraid, and I went and hid your talent in the ground. Here, you have what is yours." The fear-driven burial and the defensive return ("here, you have what is yours") is the Christological portrait of the servant who relates to God through fear of punishment rather than love of the master. The talent safely preserved but unproductive is the kingdom resource rendered useless by a theology of God as harsh creditor. The Christological counter: the master who says "enter into my joy" is not the harsh master the one-talent servant feared.</p>',
    "26": '<p>A direct revelation: "But his master answered him, \'You wicked and slothful servant! You knew that I reap where I have not sown and gather where I scattered no seed?\'" The master\'s response accepts the one-talent servant\'s premise and turns it against him: even if the master were extractive, the servant should have worked harder. The "wicked and slothful" (<em>ponēre kai oknēre</em>) verdict is the Christological judgment: the servant who believed his master was harsh should have acted from that belief, not used it as an excuse for inaction.</p>',
    "27": '<p>A revelation of God: "Then you ought to have invested my money with the bankers, and at my coming I should have received what was my own with interest." The minimum expectation — invest with bankers for interest — is the Christological baseline: even the most cautious stewardship produces something. The buried talent produces nothing. The kingdom has no room for the servant who does nothing with what was entrusted, even if the reason is excessive caution rather than malice.</p>',
    "28": '<p>A revelation of God: "So take the talent from him and give it to him who has the ten talents." The reallocation of the one talent to the ten-talent servant is the Christological kingdom economy: resources follow faithfulness, not need. The productive servant receives more; the unproductive servant loses what he had. The apparent unfairness dissolves when the talent is understood as entrusted for kingdom use — it belongs with the one who will use it.</p>',
    "29": '<p>A direct revelation: "For to everyone who has, more will be given, and he will have an abundance. But from the one who has not, even what he has will be taken away." The restating of the kingdom-abundance principle (already stated in 13:12) is the Christological law of the kingdom\'s economy: faithfulness generates abundance; unfaithfulness results in loss. The principle is eschatological, not merely pragmatic. The "to everyone who has" refers to faithful use of what was given; the "has not" refers to the servant who never genuinely engaged with the master\'s resources.</p>',
    "30": '<p>A direct revelation: "And cast the worthless servant into the outer darkness. In that place there will be weeping and gnashing of teeth." The final occurrence of the outer-darkness and weeping-and-gnashing formula in Matthew (8:12; 13:42, 50; 22:13; 24:51; 25:30) closes the Talents parable with the eschatological judgment on unfaithfulness. The "worthless servant" (<em>ton achreion doulon</em>) — not malicious but useless — is the Christological verdict on inaction. The talent-burier is not punished for rebellion but for the failure to act that made him worthless to the kingdom\'s purposes.</p>',
    "31": '<p>A direct revelation: "When the Son of Man comes in his glory, and all the angels with him, then he will sit on his glorious throne." The Sheep and Goats passage opens with the most explicit eschatological Christology in Matthew: the Son of Man\'s glorious coming with all the angels and his throne-sitting is Dan 7:13-14 made specific. The glory, the angels, and the throne are the attributes of the divine judge in Daniel; Jesus applies them to himself at the final judgment. The throne of judgment is the throne of the Son of Man.</p>',
    "32": '<p>A direct revelation: "Before him will be gathered all the nations, and he will separate people one from another as a shepherd separates the sheep from the goats." The gathering of all nations — every people group, every individual — before the Son of Man\'s throne is the Christological claim of universal sovereignty. The shepherd who separates sheep from goats is YHWH the divine shepherd (Ezek 34:17: "I will judge between sheep and sheep, between rams and male goats"). Jesus assumes the divine shepherd\'s role in the final separation.</p>',
    "33": '<p>A direct revelation: "And he will place the sheep on his right and the goats on his left." The right-and-left placement of sheep and goats is the Christological organization of the final judgment: the right hand of the king is the place of honor and blessing (v.34), the left is the place of curse (v.41). The one who determines the placement — the Son of Man on his throne — is the judge whose verdict is both personal ("I was hungry") and cosmic (universal judgment).</p>',
    "34": '<p>A direct revelation: "Then the King will say to those on his right, \'Come, you who are blessed by my Father, inherit the kingdom prepared for you from the foundation of the world.\'" The Son of Man is now addressed as "the King" — the royal title of the one who inherited all authority (Dan 7:14: "dominion, glory, and a kingdom"). "Blessed by my Father" connects the Son\'s judgment to the Father\'s blessing — the shared verdict of the divine persons. The kingdom prepared "from the foundation of the world" is the eschatological gift that was always the Son\'s to give to those the Father has given him (John 17:2).</p>',
    "35": '<p>A direct revelation: "For I was hungry and you gave me food, I was thirsty and you gave me drink, I was a stranger and you welcomed me." The first three identifications — hungry, thirsty, stranger — are the vulnerable conditions in which the King identifies himself with those who suffer. The Christological claim is extraordinary: the one who fed five thousand was himself hungry; the one who offered living water was thirsty; the Son who was "from Nazareth of Galilee" (21:11) knows what it is to be a stranger. The King speaks from genuine solidarity with the conditions he names.</p>',
    "36": '<p>A direct revelation: "I was naked and you clothed me, I was sick and you visited me, I was in prison and you came to me." The three further identifications — naked, sick, imprisoned — continue the catalog of vulnerability. The one who was stripped of his garments at the crucifixion (27:35) knows nakedness; the one who healed the sick knows sickness from the inside of compassion; the one who was imprisoned by the Sanhedrin before being handed to Pilate knows incarceration. The King\'s identification with the vulnerable is not metaphorical but embodied in his own passion.</p>',
    "37": '<p>A revelation of God: "Then the righteous will answer him, saying, \'Lord, when did we see you hungry and feed you, or thirsty and give you drink?\'" The righteous are surprised — they did not know they were serving the King. The Christological unselfconsciousness of genuine service: the sheep who cared for the vulnerable did not calculate the eschatological significance of their actions. They served because the need was before them, not because they expected eschatological commendation. The surprise is the mark of the genuinely righteous action: done without awareness of its ultimate significance.</p>',
    "38": '<p>A revelation of God: "And when did we see you a stranger and welcome you, or naked and clothe you?" The continuation of the righteous\'s surprised question reinforces the Christological anonymity of genuine service: they saw no distinguishing mark on the hungry, the stranger, the naked. They saw need and met it. The Christological revelation that the King was present in each needy person is the eschatological disclosure of what was always true but invisible during the age of service.</p>',
    "39": '<p>A revelation of God: "And when did we see you sick or in prison and visit you?" The final pair of the surprise-question completes the catalog. The Christological point: the sheep who visited the sick and imprisoned were not doing so as a strategy for eschatological reward — they did not know who they were serving. Their service to the anonymous needy was service to the anonymous King. The disclosure at the judgment is the unveiling of the identity that was always present but hidden.</p>',
    "40": '<p>A direct revelation: "And the King will answer them, \'Truly, I say to you, as you did it to one of the least of these my brothers, you did it to me.\'" The "you did it to me" is the highest Christological identification in the entire Gospel. The King identifies himself with the most vulnerable — "the least of these my brothers." The phrase "my brothers" identifies the vulnerable as the King\'s family — those with whom he is in solidarity. The Christological solidarity: what is done to the least is done to the one who called the least his brothers. The identity is real, not merely symbolic.</p>',
    "41": '<p>A direct revelation: "Then he will say to those on his left, \'Depart from me, you cursed, into the eternal fire prepared for the devil and his angels.\'" The "depart from me" — the words of eschatological exclusion — echo 7:23 ("I never knew you; depart from me"). The eternal fire prepared for the devil and his angels is the Christological specificity of the judgment\'s destination: the punishment was not prepared for humans but for the adversary and his agents. Those who receive it have aligned themselves, by their failure of service, with the adversary\'s refusal of the vulnerable.</p>',
    "42": '<p>A direct revelation: "For I was hungry and you gave me no food, I was thirsty and you gave me no drink." The same six categories of need — now unmet — are the Christological indictment of the goats. The same King who identified himself with the vulnerable now identifies the failure to serve the vulnerable as failure to serve him. The symmetry is precise: every act of service and every failure to serve is weighed against the same standard — the King who was hungry, thirsty, naked, sick, imprisoned.</p>',
    "43": '<p>A direct revelation: "I was a stranger and you did not welcome me, naked and you did not clothe me, sick and in prison and you did not visit me." The three further failures complete the indictment. The Christological bearing: the neglect of the vulnerable is not a passive failure but an active refusal — the need was present and was passed by. The one who identifies himself with the needy knows what it is to be passed by, and the memory of each passing becomes the content of the judgment.</p>',
    "44": '<p>A revelation of God: "Then they also will answer, saying, \'Lord, when did we see you hungry or thirsty or a stranger or naked or sick or in prison, and did not minister to you?\'" The goats\' surprised question mirrors the sheep\'s: they did not know either. The Christological symmetry of the ignorance is instructive: both groups were unaware of the King\'s presence in the needy. The difference is not awareness but action: the sheep acted when they saw need; the goats did not. The question "when did we see you?" reveals the category error — they would have acted if they had recognized the King, but that is precisely the point they missed.</p>',
    "45": '<p>A direct revelation: "Then he will answer them, saying, \'Truly, I say to you, as you did not do it to one of the least of these, you did not do it to me.\'" The negative form of the great identification — "you did not do it to me" — closes the Christological circle. Every failure to serve the needy is a failure to serve the King. The "least of these" who were passed by were the King in disguise; every act of passing by was an act of rejecting the sovereign. The judgment reveals that the goats were making choices of ultimate consequence while thinking they were making choices of no consequence.</p>',
    "46": '<p>A direct revelation: "And these will go away into eternal punishment, but the righteous into eternal life." The final verse of ch.25 and the final verse of the fifth discourse presents the two eternal destinations: eternal punishment and eternal life. The Christological framing: both destinies are determined by the same judge, the Son of Man on his throne, who is simultaneously the King who identifies with the vulnerable and the judge who separates on the basis of that identification. The discourse that began with ten virgins waiting for the bridegroom ends with all nations sorted before the King — the same person, the same standard, the same eschatological reality.'
  }
}

def main():
    existing = load_comm('mkt-christ', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-christ', 'matthew', existing)
    print('Matthew 25 mkt-christ written.')

if __name__ == '__main__':
    main()
